"use client"

import useSWR from "swr"
import { ScrollReveal, StaggerContainer, StaggerItem, Parallax } from "@/components/scroll-animations"
import { Brain, Code, Database, Cpu, GraduationCap, Award } from "lucide-react"
import { Spinner } from "@/components/ui/spinner"
import type { Profile } from "@/lib/models"

const iconMap: Record<string, React.ElementType> = {
  Brain, Code, Database, Cpu, GraduationCap, Award
}

const fetcher = (url: string) => fetch(url).then(res => res.json())

export function AboutSection() {
  const { data: profile, isLoading } = useSWR<Profile>(
    "/api/profile",
    fetcher,
    { revalidateOnFocus: false }
  )

  if (isLoading) {
    return (
      <section id="about" className="py-32 px-6 relative flex justify-center">
        <Spinner className="w-8 h-8 text-primary" />
      </section>
    )
  }

  // Fallbacks if DB is empty
  const bio = profile?.bio && profile.bio.length > 0 ? profile.bio : [
    "I am an AI/ML Researcher and Engineer dedicated to building next-generation artificial intelligence systems.",
    "My passion lies in bridging the gap between theoretical research and practical, real-world implementations."
  ]

  const skills = profile?.skills && profile.skills.length > 0 ? profile.skills : [
    { name: "Deep Learning", icon: "Brain", level: 95 },
    { name: "Computer Vision", icon: "Cpu", level: 90 },
    { name: "NLP", icon: "Code", level: 88 },
    { name: "Big Data", icon: "Database", level: 85 },
  ]

  const highlights = profile?.highlights && profile.highlights.length > 0 ? profile.highlights : [
    { icon: "GraduationCap", label: "University", value: "Computer Science" },
    { icon: "Award", label: "Experience", value: "3+ Years" },
    { icon: "Brain", label: "Models Built", value: "25+" },
    { icon: "Database", label: "Research", value: "10+" },
  ]

  return (
    <section id="about" className="py-32 px-6 relative">
      <div className="max-w-6xl mx-auto">
        <ScrollReveal>
          <div className="text-center mb-16">
            <h2 className="text-4xl md:text-5xl font-bold mb-4">
              About <span className="text-primary">Me</span>
            </h2>
            <p className="text-muted-foreground text-lg max-w-2xl mx-auto">
              {profile?.title || "Building intelligent systems and exploring the frontiers of AI"}
            </p>
          </div>
        </ScrollReveal>
        
        <div className="grid lg:grid-cols-2 gap-16 items-center">
          <Parallax offset={30}>
            <ScrollReveal delay={0.2}>
              <div className="space-y-6">
                {bio.map((paragraph, idx) => (
                  <p key={idx} className="text-lg text-muted-foreground leading-relaxed">
                    {paragraph}
                  </p>
                ))}
                
                {/* Skill bars */}
                <div className="space-y-4 pt-6">
                  {skills.map((skill, idx) => (
                    <SkillBar key={skill.name} skill={skill} delay={idx * 0.1} />
                  ))}
                </div>
              </div>
            </ScrollReveal>
          </Parallax>
          
          <StaggerContainer className="grid grid-cols-2 gap-6" staggerDelay={0.15}>
            {highlights.map((item) => {
              const Icon = iconMap[item.icon as string] || Code;
              return (
                <StaggerItem key={item.label}>
                  <div className="p-6 rounded-2xl border border-border/50 bg-card/50 backdrop-blur-sm hover:border-primary/50 transition-colors group h-full flex flex-col justify-center items-center text-center">
                    <div className="w-12 h-12 rounded-xl bg-primary/10 flex items-center justify-center mb-4 group-hover:bg-primary/20 transition-colors">
                      <Icon className="w-6 h-6 text-primary" />
                    </div>
                    <div className="text-2xl md:text-3xl font-bold text-foreground mb-1">{item.value}</div>
                    <div className="text-sm text-muted-foreground">{item.label}</div>
                  </div>
                </StaggerItem>
              )
            })}
          </StaggerContainer>
        </div>
      </div>
    </section>
  )
}

function SkillBar({ skill, delay }: { skill: any; delay: number }) {
  const Icon = iconMap[skill.icon as string] || Code;
  return (
    <ScrollReveal delay={delay}>
      <div className="space-y-2">
        <div className="flex items-center justify-between">
          <div className="flex items-center gap-2">
            <Icon className="w-4 h-4 text-primary" />
            <span className="font-medium text-foreground">{skill.name}</span>
          </div>
          <span className="text-sm text-muted-foreground">{skill.level || 90}%</span>
        </div>
        <div className="h-2 rounded-full bg-muted overflow-hidden">
          <div
            className="h-full rounded-full bg-gradient-to-r from-primary to-accent transition-all duration-1000"
            style={{ width: `${skill.level || 90}%` }}
          />
        </div>
      </div>
    </ScrollReveal>
  )
}
